CREATE TABLE IF NOT EXISTS `lab_repo` (
  `mstRepoKey` int NOT NULL AUTO_INCREMENT,
  `Title` varchar(100) NOT NULL,
  `RTFData` longtext,
  `HTMLData` longtext,
  `GrpKey` int NOT NULL,
  `IncludeHeader` tinyint(1) DEFAULT '1',
  `IncludeFooter` tinyint(1) DEFAULT '1',
  `charge_id` int DEFAULT '0',
  PRIMARY KEY (`mstRepoKey`),
  UNIQUE KEY `Title` (`Title`),
  KEY `GrpKey` (`GrpKey`),
  KEY `charge_id` (`charge_id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb3;
INSERT IGNORE INTO `lab_repo` (`mstRepoKey`, `Title`, `RTFData`, `HTMLData`, `GrpKey`, `IncludeHeader`, `IncludeFooter`, `charge_id`) VALUES (0,'Manual',NULL,NULL,0,1,1,0),(1,'COMPLETE BLOOD COUNT (CBC) ',NULL,'<table border=\"0\" cellpadding=\"3\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:lightgray\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Unit</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Bio. Ref. Interval</strong></td>\n		</tr>\n		<tr>\n			<td><strong>Haemoglobin</strong></td>\n			<td>{HB}</td>\n			<td>gm%</td>\n			<td>12-16</td>\n		</tr>\n		<tr>\n			<td><strong>TLC</strong></td>\n			<td>{TLC}</td>\n			<td>per cu mm</td>\n			<td>4000-11000</td>\n		</tr>\n		<tr>\n			<td><strong>DLC</strong></td>\n			<td>&nbsp;</td>\n			<td>&nbsp;</td>\n			<td>&nbsp;</td>\n		</tr>\n		<tr>\n			<td><strong>Neutrophils</strong></td>\n			<td>{NEU}</td>\n			<td>%</td>\n			<td>45-70</td>\n		</tr>\n		<tr>\n			<td><strong>Lymphocytes</strong></td>\n			<td>{LYMP}</td>\n			<td>%</td>\n			<td>20-45</td>\n		</tr>\n		<tr>\n			<td><strong>Eosinophils</strong></td>\n			<td>{EOSIN}</td>\n			<td>%</td>\n			<td>1-8</td>\n		</tr>\n		<tr>\n			<td><strong>Monocytes</strong></td>\n			<td>{MONO}</td>\n			<td>%</td>\n			<td>1-6</td>\n		</tr>\n		<tr>\n			<td><strong>Basophils</strong></td>\n			<td>{BASO}</td>\n			<td>%</td>\n			<td>&lt; 1%</td>\n		</tr>\n		<tr>\n			<td><strong>RBC&nbsp;Count</strong></td>\n			<td>{RBC}</td>\n			<td>Million/cm</td>\n			<td>4.2-5.5</td>\n		</tr>\n		<tr>\n			<td><strong>PCV</strong></td>\n			<td>{PCV}</td>\n			<td>%</td>\n			<td>40 - 54</td>\n		</tr>\n		<tr>\n			<td><strong>MCV</strong></td>\n			<td>{MCV}</td>\n			<td>fl</td>\n			<td>80-100</td>\n		</tr>\n		<tr>\n			<td><strong>MCH</strong></td>\n			<td>{mch}</td>\n			<td>pg</td>\n			<td>28-35</td>\n		</tr>\n		<tr>\n			<td><strong>MCHC</strong></td>\n			<td>{MCHC}</td>\n			<td>g/dl</td>\n			<td>30-38</td>\n		</tr>\n		<tr>\n			<td><strong>Platelet Count</strong></td>\n			<td>{PLATELET}</td>\n			<td>Lakh per cu mm</td>\n			<td>1.5-4.5</td>\n		</tr>\n		<tr>\n			<td><strong>ESR</strong></td>\n			<td>{ESR1}</td>\n			<td>Mm for 1st hr.</td>\n			<td>&lt; 9 &gt;</td>\n		</tr>\n	</tbody>\n</table>\n',6,1,1,382),(2,'LIVER FUNCTION TEST (LFT) ,SERUM',NULL,'<p>&nbsp;(Spectrophotometry) &nbsp;</p>\n\n<table border=\"0\" cellpadding=\"3\" cellspacing=\"0\" style=\"width:800px\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:lightgray\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Unit</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Bio. Ref. Interval</strong></td>\n		</tr>\n		<tr>\n			<td>Bilirubin (Total)</td>\n			<td>{SERBIL}</td>\n			<td>mg/dl</td>\n			<td>0.3-1.2</td>\n		</tr>\n		<tr>\n			<td>Bilirubin (Direct)</td>\n			<td>{BD}</td>\n			<td>mg/dl</td>\n			<td>&lt; 0.3</td>\n		</tr>\n		<tr>\n			<td>Bilirubin (Indirect)</td>\n			<td>{BI}</td>\n			<td>mg/dl</td>\n			<td>&lt; 0.8</td>\n		</tr>\n		<tr>\n			<td>SGOT / Aspartate Aminotransferase (AST)</td>\n			<td>{SGOT}</td>\n			<td>U/L</td>\n			<td>&lt; 35</td>\n		</tr>\n		<tr>\n			<td>SGPT/ Alanine Aminotransferase (ALT)</td>\n			<td>{SGPT}</td>\n			<td>U/L</td>\n			<td>&lt; 40</td>\n		</tr>\n		<tr>\n			<td>Alkaline Phosphatase (Total)</td>\n			<td>{SALKALINE}</td>\n			<td>U/L</td>\n			<td>25-140</td>\n		</tr>\n		<tr>\n			<td>Protein(Total)</td>\n			<td>{TOTPRO}</td>\n			<td>gm/dl</td>\n			<td>6.2-8.0</td>\n		</tr>\n		<tr>\n			<td>Albumin</td>\n			<td>{ALBU}</td>\n			<td>gm/dl</td>\n			<td>3.8-5.4</td>\n		</tr>\n		<tr>\n			<td>Globulin</td>\n			<td>{GLOB}</td>\n			<td>gm/dl</td>\n			<td>1.8-3.6</td>\n		</tr>\n		<tr>\n			<td>A:G Ratio</td>\n			<td>{AGR}</td>\n			<td>&nbsp;</td>\n			<td>1.1-2.0</td>\n		</tr>\n	</tbody>\n</table>\n',1,1,1,286),(3,'RENAL FUNCTION TEST (KFT)',NULL,'<table border=\"0\" cellpadding=\"3\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:lightgray\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Unit</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Bio. Ref. Interval</strong></td>\n		</tr>\n		<tr>\n			<td>Urea</td>\n			<td>{BU}&nbsp;</td>\n			<td>mg/dL</td>\n			<td>11-37</td>\n		</tr>\n		<tr>\n			<td>Creatinine</td>\n			<td>{SC}</td>\n			<td>mg/dL</td>\n			<td>0.6-1.4</td>\n		</tr>\n		<tr>\n			<td>Uric Acid</td>\n			<td>{SUA}</td>\n			<td>mg/dL</td>\n			<td>2.6-7.2</td>\n		</tr>\n		<tr>\n			<td>Calcium</td>\n			<td>{SCA}</td>\n			<td>mg/dL</td>\n			<td>8.6-10.3</td>\n		</tr>\n		<tr>\n			<td>Sodium</td>\n			<td>{SS}</td>\n			<td>m Mol /L</td>\n			<td>135-155</td>\n		</tr>\n		<tr>\n			<td>Potassium&nbsp;</td>\n			<td>{SP}</td>\n			<td>m Mol /L</td>\n			<td>3.5-5.5</td>\n		</tr>\n	</tbody>\n</table>\n',1,1,1,289),(4,'C-Reactive Protein(C.R.P.)',NULL,'<table border=\"0\" cellpadding=\"5\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:lightgrey\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgrey\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgrey\"><strong>Unit</strong></td>\n			<td style=\"background-color:lightgrey\"><strong>Bio.Ref. Interval&nbsp;</strong></td>\n		</tr>\n		<tr>\n			<td style=\"vertical-align:top\">C-Reactive Protein(C.R.P.)<br />\n			&nbsp;</td>\n			<td style=\"vertical-align:top\">{CRP}<br />\n			{CRPSTATUS}</td>\n			<td style=\"vertical-align:top\">mg/l</td>\n			<td style=\"vertical-align:top\">Adults : &lt; 6 mg/L<br />\n			New Bron Baby&nbsp; upto 3 weeks :&nbsp; &lt;4.1 mg/L<br />\n			Infants and Children : &lt;2.8 mg/L</td>\n		</tr>\n	</tbody>\n</table>\n',1,1,1,387),(5,'F.N.A.C.',NULL,'<h3><em><strong>CYTOPATHOLOGY</strong></em></h3>\n\n<h3>F.N.A.C.</h3>\n\n<p>{BPART}</p>\n\n<p><strong>REPORT :</strong></p>\n\n<p>&nbsp;</p>\n',5,1,1,351),(6,'Anti - HIV (I & II) ANTIBODIES',NULL,'<table border=\"0\" cellpadding=\"3\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:lightgrey; text-align:left; vertical-align:top\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgrey; text-align:left; vertical-align:top\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgrey; text-align:left; vertical-align:top\"><strong>Method</strong></td>\n		</tr>\n		<tr>\n			<td style=\"text-align:left; vertical-align:top\">Anti - HIV I &amp;&nbsp;II<br />\n			ANTIBODIES</td>\n			<td style=\"text-align:left; vertical-align:top\">{HIV1}</td>\n			<td style=\"text-align:left; vertical-align:top\">IMMUNOCHROMATOGRAPHY</td>\n		</tr>\n	</tbody>\n</table>\n\n<p><strong>INTERPRETATION :</strong> &nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;<br />\n1.This is only a screening test.All reactive sample should be confirmatory test. &nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;<br />\n2.A negative result implies that no Anti HIV &ndash; II antibodies have been detected in the sample by this method. &nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;<br />\n3.A positive result suggests the possibilities of HIV-I and / or HIV-II infection.However these results must be verified by a confirmatory test (IFA / WESTERN BLOT I-II) before pronouncing the patient positive for HIV-I and / r HIV-II infection.&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;</p>\n',12,1,1,295),(7,'HBsAg',NULL,'<table border=\"0\" cellpadding=\"3\" cellspacing=\"0\" style=\"height:82px; width:100%\">\n	<tbody>\n		<tr>\n			<td style=\"background-color:#bfbfbf; height:15pt; text-align:left; vertical-align:top; white-space:nowrap; width:91pt\"><strong>Test&nbsp; Name</strong></td>\n			<td style=\"background-color:#bfbfbf; height:15pt; text-align:left; vertical-align:top; white-space:nowrap; width:63pt\"><strong>Result</strong></td>\n			<td style=\"background-color:#bfbfbf; height:15pt; text-align:left; vertical-align:top; white-space:normal; width:198pt\"><strong>Method</strong></td>\n		</tr>\n		<tr>\n			<td style=\"vertical-align:top\">HBsAg*<br />\n			(AUSTRALIA ANTIGEN)<br />\n			&nbsp;</td>\n			<td style=\"vertical-align:top\">{HBsAG}</td>\n			<td style=\"vertical-align:top\">IMMUNOCHROMATOGRAPHY</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>Note: This is only a screening test. All reactive sample should be confirmatory test.Therefore for a definitive diagnosis,&nbsp;&nbsp; &nbsp;the patient&rsquo;s clinical history, symptomatology as well as serological data,should be considered.Additional follow up testing&nbsp;&nbsp;using available clinical methods(along with repeat card test)is required,if card test is non-reactive with persisting clinical symptoms.False positive results can be obtained due to the presence of other antigens or elevated levels of RF factor.The presence of HBsAg in the serum indicates either a chronic or acute infection with virus,HBeAG may be advised for further evaluation.</p>\n',12,1,1,336),(8,'Serum Prolactin',NULL,'<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td><strong>Test Name</strong></td>\n			<td><strong>Observed Values</strong></td>\n			<td><strong>Unit</strong></td>\n			<td><strong>Normal Values</strong></td>\n		</tr>\n		<tr>\n			<td>Serum Prolactin</td>\n			<td>{SProlactin}</td>\n			<td>ng/ml</td>\n			<td>5-35</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n',13,1,1,225),(9,'Vitamin D',NULL,'<h3>Bio-Chemistry</h3>\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td>Test Name</td>\n			<td>Observed Values</td>\n			<td>Unit</td>\n			<td>Normal Values</td>\n		</tr>\n		<tr>\n			<td style=\"text-align:left; vertical-align:top\">Vitamin D</td>\n			<td style=\"text-align:center; vertical-align:top\">{VITD}</td>\n			<td style=\"text-align:left; vertical-align:top\">ng/ml</td>\n			<td style=\"text-align:left; vertical-align:top\"><strong>Reference Range:</strong><br />\n			<em>Deficent : &lt; 20<br />\n			Insufficent : 20-29<br />\n			Sufficent : 30-100<br />\n			Potential Toxicity &gt; 100</em></td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n',13,1,1,162),(10,'Glycosylated Hemoglobin (HbA1c)*,EDTA BLOOD',NULL,'<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:100%\">\n	<tbody>\n		<tr>\n			<td>\n			<p><strong>Test Name</strong></p>\n			</td>\n			<td>\n			<p><strong>Result</strong></p>\n			</td>\n			<td>\n			<p><strong>Unit</strong></p>\n			</td>\n			<td>\n			<p><strong>Bio.Ref.Interval</strong></p>\n			</td>\n			<td>\n			<p><strong>Method</strong></p>\n			</td>\n		</tr>\n		<tr>\n			<td>\n			<p><strong>GLYCOSYLATED HAEMOGLOBIN (HBA1C) *</strong>, EDTA BLOOD<br />\n			Glycosylated Haemoglobin (HbA1c)</p>\n			</td>\n			<td>\n			<p>{HBA1C}</p>\n			</td>\n			<td>\n			<p>%</p>\n			</td>\n			<td>\n			<p>&lt; 5.7 Non diabetic<br />\n			adults&gt;=18 years<br />\n			5.7-6.4 At risk<br />\n			(Prediabetes)<br />\n			&gt;= 6.5 Diabetes<br />\n			(As per ADA)</p>\n			</td>\n			<td>\n			<p>QUANTITATIVE TURBIDIMETRIC IMMUNOASSAY</p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p><strong>Interpretation:</strong><br />\n&nbsp;1 HbA1c testing provides an index of any blood glucose over past 2 to 4 months.</p>\n\n<p>&nbsp;2 Approx 50% of HbA1c determined by previous 1 month and 75% during previous 2 months.</p>\n\n<p>3 Hba1c levels are lowered by&nbsp;</p>\n\n<p>(a) shortened RBC survival or lower mean RBC are eg. hemolysis,transfusions,recovery from acure blood loss.</p>\n\n<p>(b) Hyperglycernia decreases erythrocyte survival on&nbsp;long term,so in poorly controlled patients may underestimate their mean plasma glucose concertration.</p>\n\n<p>(c) Accuracy also effected by hemoglobinopathies&nbsp;HbSS,HbSC,HbCC) associated with high cell turnovers chronic&nbsp;alcohol or opiate&nbsp;use,iron deficency and lead&nbsp;</p>\n\n<p>&nbsp; &nbsp; Poisoning and advanced chronic kidney disease.</p>\n\n<p>ADA criteria&nbsp;between HbA1c and plasma glucose levels.&nbsp; &nbsp;</p>\n\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"height:5px; width:500px\">\n	<tbody>\n		<tr>\n			<td>Hemoglobin a/c(%)&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</td>\n			<td>\n			<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;Approximate mean plasma</p>\n\n			<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Glucose (mg/dl)</p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\n	<tbody>\n		<tr>\n			<td>5</td>\n			<td>97</td>\n		</tr>\n		<tr>\n			<td>6</td>\n			<td>126</td>\n		</tr>\n		<tr>\n			<td>7</td>\n			<td>154</td>\n		</tr>\n		<tr>\n			<td>8</td>\n			<td>183</td>\n		</tr>\n		<tr>\n			<td>9</td>\n			<td>212</td>\n		</tr>\n		<tr>\n			<td>10</td>\n			<td>240</td>\n		</tr>\n		<tr>\n			<td>11</td>\n			<td>269</td>\n		</tr>\n		<tr>\n			<td>12</td>\n			<td>298</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>Uncertainity in accuracy in children.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>\n\n<p>&nbsp; &nbsp;&nbsp;</p>\n\n<p>&nbsp;</p>\n',1,1,1,337),(11,'Semen Analaysis',NULL,'<p><strong>PHYSICAL CHARACTERISTICS</strong></p>\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:500px\">\n	<tbody>\n		<tr>\n			<td>Volume</td>\n			<td>{vol}</td>\n			<td>&nbsp;</td>\n		</tr>\n		<tr>\n			<td>Colour</td>\n			<td>{sem_color}</td>\n			<td>PEARLY WHITE</td>\n		</tr>\n		<tr>\n			<td>Reaction</td>\n			<td>{semen_reaction}</td>\n			<td>ALKALINE</td>\n		</tr>\n		<tr>\n			<td>Viscosity</td>\n			<td>{Viscosity}</td>\n			<td>VISCOUS</td>\n		</tr>\n		<tr>\n			<td>Liquification Time</td>\n			<td>{LIQTIME} min</td>\n			<td>&lt; 30 MIN</td>\n		</tr>\n	</tbody>\n</table>\n\n<p><strong>MICROSCOPIC FEATURES</strong></p>\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:500px\">\n	<tbody>\n		<tr>\n			<td>Total Sperm Count</td>\n			<td>{TOTSPCOUNT} millions /ml</td>\n			<td>15-200</td>\n		</tr>\n		<tr>\n			<td>Active</td>\n			<td>{semen_active} %</td>\n			<td>&gt;60 %</td>\n		</tr>\n		<tr>\n			<td>Sluggish</td>\n			<td>{SLUGGISH} %</td>\n			<td>&lt;30 %</td>\n		</tr>\n		<tr>\n			<td>Non Motile</td>\n			<td>{NONMOTILE} %</td>\n			<td>&lt;20 %</td>\n		</tr>\n		<tr>\n			<td>Abnormal Forms</td>\n			<td>{Abnormal} %</td>\n			<td>&lt;30 %</td>\n		</tr>\n		<tr>\n			<td>Pus Cells</td>\n			<td>{PUSCELL} /HPF</td>\n			<td>NIL</td>\n		</tr>\n		<tr>\n			<td>Epithelial cells</td>\n			<td>{EPITH} /HPF</td>\n			<td>NIL</td>\n		</tr>\n		<tr>\n			<td>RBCs</td>\n			<td>{sRBC} /HPF</td>\n			<td>NIL</td>\n		</tr>\n		<tr>\n			<td>Remarks</td>\n			<td>{SEMENREMARKS}</td>\n			<td>&nbsp;</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n',12,1,1,243),(12,'ADA-MTB',NULL,'<h3><strong>ADA-MTB</strong></h3>\n\n<p>FOR THE DETERMINATION OF ADENOSINE DEAMINASE ACTIVITY IN&nbsp; SERUM, PLASMA &amp; BIOLOGICAL FLUIDS</p>\n\n<p>{THEAD} :{THV}</p>\n\n<p><strong>Reference Values :</strong></p>\n\n<table align=\"left\" border=\"1\" cellpadding=\"5\" cellspacing=\"0\" style=\"width:500px\">\n	<tbody>\n		<tr>\n			<td style=\"text-align:left; vertical-align:top\">Serum,Plasma,Pleural,<br />\n			Pericadial &amp; Ascitic Fluids</td>\n			<td style=\"text-align:left; vertical-align:top\">Normal : &lt;30 U/L<br />\n			Suspect : 30- 40 U/L<br />\n			Strong Suspect : 41 - 60 U/L<br />\n			Positive : &gt;60 u/l</td>\n		</tr>\n		<tr>\n			<td style=\"text-align:left; vertical-align:top\">CSF</td>\n			<td style=\"text-align:left; vertical-align:top\">Normal : &lt; 10 U/L<br />\n			Positive : &gt; 10 U/L</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>&nbsp;</p>\n',5,1,1,422),(13,'Blood Glucose Random',NULL,'<table border=\"0\" cellpadding=\"5\" cellspacing=\"0\" style=\"width:100%\">\n	<thead>\n		<tr>\n			<td style=\"background-color:lightgray\"><strong>Test Name</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Result</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Unit</strong></td>\n			<td style=\"background-color:lightgray\"><strong>Bio. Ref. Interval</strong></td>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td>&nbsp;</td>\n			<td>&nbsp;</td>\n			<td>&nbsp;</td>\n			<td>&nbsp;</td>\n		</tr>\n		<tr>\n			<td>BLOOD GLUCOSE RANDOM<br />\n			&nbsp;</td>\n			<td>{AGR1}</td>\n			<td>mg/dL</td>\n			<td>70.00-140.00</td>\n		</tr>\n	</tbody>\n</table>\n\n<p>Note</p>\n\n<ol>\n	<li>The diagnosis of Diabetes requires a fasting plasma glucose of &gt; or = 126 mg/dL and/or a random / 2 hr post glucose value of &gt; or = 200 mg/dL on at least 2 occasions.</li>\n	<li>Very low glucose levels cause severe CNS dysfunction.</li>\n	<li>Very high glucose levels (&gt;450 mg/dL in adults) may result in Diabetic Ketoacidosis &amp; is considered critical.</li>\n</ol>\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>\n',1,1,1,397),(14,'Prothrombin Time With INR',NULL,'<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:500px\">\n	<tbody>\n		<tr>\n			<td>Patients Prothombin Time Value</td>\n			<td>&nbsp;{PPTV} sec.</td>\n		</tr>\n		<tr>\n			<td>Control Prothombin Time Value<br />\n			(<em>Normal Range is 11 to 16sec.</em>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; )</td>\n			<td>&nbsp;{CPTV} sec.</td>\n		</tr>\n		<tr>\n			<td>Patient INR Value</td>\n			<td>&nbsp;{PINRV}</td>\n		</tr>\n		<tr>\n			<td>Oral Anticoauglant Therapeutic Range</td>\n			<td>&nbsp;{OATR}</td>\n		<